mapper.select:
SELECT EXISTS
(
  SELECT *
  FROM fx_summer_time
  WHERE target_year = #{targetYear}
)

mapper.update:
UPDATE fx_summer_time
SET
   apply_start = #{applyStart}
  ,apply_end   = #{applyEnd}
WHERE target_year = #{targetYear}

UPDATE fx_summer_time
SET
   target_year = "{summerTime.targetYear}
  ,apply_start = #{summerTime.applyStart}
  ,apply_end   = #{summerTime.applyEnd}
WHERE target_year = #{targetYear}
